@* Displays a single task with title, assignee, priority badge, due date, and move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <div class="d-flex justify-content-between align-items-start">
            <h6 class="card-title mb-1">@Task.Title</h6>
            <span class="badge @PriorityClass">@Task.Priority</span>
        </div>
        <p class="card-text text-muted small mb-1">@Task.Assignee</p>
        <p class="card-text small mb-2">@Task.DueDate.ToString("MMM dd")</p>
        <div class="d-flex gap-1">
            @if (CanMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveLeft.InvokeAsync(Task)">
                    &larr; Move Left
                </button>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveRight.InvokeAsync(Task)">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@* Inline form for creating a new task within a column *@

@if (!IsVisible)
{
    <button class="btn btn-outline-primary btn-sm w-100" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="card border-primary">
        <div class="card-body p-2">
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Title"
                       @bind="title" @bind:event="oninput" />
            </div>
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Assignee"
                       @bind="assignee" @bind:event="oninput" />
            </div>
            <div class="mb-2">
                <select class="form-select form-select-sm" @bind="priority">
                    <option value="High">High</option>
                    <option value="Medium">Medium</option>
                    <option value="Low">Low</option>
                </select>
            </div>
            <div class="mb-2">
                <input type="date" class="form-control form-control-sm" @bind="dueDate" />
            </div>
            <div class="d-flex gap-1">
                <button class="btn btn-primary btn-sm" @onclick="Save" disabled="@saving">
                    @(saving ? "Saving..." : "Save")
                </button>
                <button class="btn btn-secondary btn-sm" @onclick="Cancel" disabled="@saving">Cancel</button>
            </div>
            @if (errorMessage is not null)
            {
                <div class="text-danger small mt-1">@errorMessage</div>
            }
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }
    [Parameter] public ITaskService TaskService { get; set; } = default!;

    public bool IsVisible { get; private set; }

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool saving;
    private string? errorMessage;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        IsVisible = false;
        ResetFields();
    }

    private void ResetFields()
    {
        title = "";
        assignee = "";
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
        errorMessage = null;
    }

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title))
        {
            errorMessage = "Title is required.";
            return;
        }

        saving = true;
        errorMessage = null;
        try
        {
            var created = await TaskService.CreateTaskAsync(title.Trim(), assignee.Trim(), priority, dueDate);
            await OnTaskCreated.InvokeAsync(created);
            IsVisible = false;
            ResetFields();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }
}

@* Summary statistics bar shown above the board *@

<div class="d-flex flex-wrap gap-3 mb-3 p-3 bg-light rounded">
    <div>
        <strong>Total:</strong> @TotalCount
    </div>
    <div>
        <strong>To Do:</strong> @ToDoCount
    </div>
    <div>
        <strong>In Progress:</strong> @InProgressCount
    </div>
    <div>
        <strong>Done:</strong> @DoneCount
    </div>
    <div class="@(OverdueCount > 0 ? "text-danger" : "")">
        <strong>Overdue:</strong> @OverdueCount
    </div>
</div>

@code {
    [Parameter] public int TotalCount { get; set; }
    [Parameter] public int ToDoCount { get; set; }
    [Parameter] public int InProgressCount { get; set; }
    [Parameter] public int DoneCount { get; set; }
    [Parameter] public int OverdueCount { get; set; }
}

@* Search input for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = "";
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? "");
    }
}

@* A single Kanban column showing its header, task cards, and an add-task form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@Title</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body d-flex flex-column gap-2 overflow-auto" style="max-height: 70vh;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          OnMoveLeft="OnMoveLeft"
                          OnMoveRight="OnMoveRight" />
            }

            <AddTaskForm Status="@Status"
                         TaskService="TaskService"
                         OnTaskCreated="OnTaskCreated" />
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string Title { get; set; } = default!;
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public List<TaskItem> Tasks { get; set; } = [];
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
