@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error loading tasks:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="LoadTasksAsync">Retry</button>
    </div>
}
else
{
    <BoardStatsBar TotalCount="allTasks.Count"
                   ToDoCount="todoTasks.Count"
                   InProgressCount="inProgressTasks.Count"
                   DoneCount="doneTasks.Count"
                   OverdueCount="overdueTasks.Count" />

    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <BoardColumn Title="To Do"
                     Status="To Do"
                     Tasks="filteredTodo"
                     CanMoveLeft="false"
                     CanMoveRight="true"
                     OnMoveRight="MoveRight"
                     OnTaskCreated="HandleTaskCreated"
                     TaskService="TaskService" />

        <BoardColumn Title="In Progress"
                     Status="In Progress"
                     Tasks="filteredInProgress"
                     CanMoveLeft="true"
                     CanMoveRight="true"
                     OnMoveLeft="MoveLeft"
                     OnMoveRight="MoveRight"
                     OnTaskCreated="HandleTaskCreated"
                     TaskService="TaskService" />

        <BoardColumn Title="Done"
                     Status="Done"
                     Tasks="filteredDone"
                     CanMoveLeft="true"
                     CanMoveRight="false"
                     OnMoveLeft="MoveLeft"
                     OnTaskCreated="HandleTaskCreated"
                     TaskService="TaskService" />
    </div>
}

@code {
    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = [];
    private string searchText = "";
    private bool loading = true;
    private string? errorMessage;

    // Unfiltered lists by status (for stats)
    private List<TaskItem> todoTasks => allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> inProgressTasks => allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> doneTasks => allTasks.Where(t => t.Status == "Done").ToList();
    private List<TaskItem> overdueTasks => allTasks.Where(t => t.DueDate < DateTime.Today && t.Status != "Done").ToList();

    // Filtered lists (for display in columns)
    private List<TaskItem> filteredTodo => ApplySearch(todoTasks);
    private List<TaskItem> filteredInProgress => ApplySearch(inProgressTasks);
    private List<TaskItem> filteredDone => ApplySearch(doneTasks);

    private List<TaskItem> ApplySearch(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchText))
            return tasks;
        return tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadTasksAsync();
    }

    private async Task LoadTasksAsync()
    {
        loading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private void HandleSearchChanged(string value)
    {
        searchText = value;
    }

    private async Task MoveLeft(TaskItem task)
    {
        var currentIndex = Array.IndexOf(Statuses, task.Status);
        if (currentIndex <= 0) return;

        var newStatus = Statuses[currentIndex - 1];
        await MoveTask(task, newStatus);
    }

    private async Task MoveRight(TaskItem task)
    {
        var currentIndex = Array.IndexOf(Statuses, task.Status);
        if (currentIndex < 0 || currentIndex >= Statuses.Length - 1) return;

        var newStatus = Statuses[currentIndex + 1];
        await MoveTask(task, newStatus);
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            // Update the local list to reflect the move
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private void HandleTaskCreated(TaskItem newTask)
    {
        allTasks.Add(newTask);
    }
}

